    display_height_px: 1080,
  },
  {
    type: "bash_20250124",
    name: "bash",
  },
  {
    type: "text_editor_20250124",
    name: "str_replace_based_edit_tool",
  },
];

const response = await client.messages.create({
  model: "claude-opus-4-7",
  max_tokens: 4096,
  tools,
  messages: [{
    role: "user",
    content: "打開 Chrome、登入 Google、檢查未讀 email"
  }],
});

// Claude 會回 tool_use：
// 1. screenshot — 看當前畫面
// 2. click — 點擊座標
// 3. type — 輸入文字
// 4. key — 按 Cmd+Tab 等鍵盤組合

while (response.stop_reason === "tool_use") {
  for (const block of response.content) {
    if (block.type === "tool_use") {
      const result = await executeAction(block.name, block.input);
      // 把結果（截圖 + 文字）再傳回
    }
  }
}
```

## browser-use（開源、Python）
```python
# pip install browser-use
from browser_use import Agent
from langchain_anthropic import ChatAnthropic

agent = Agent(
    task="去蝦皮買一個 iPhone 17 手機殼、預算 NT$500 以下",
    llm=ChatAnthropic(model="claude-opus-4-7"),
)
result = await agent.run()
```

agent 會：
1. 開 Chrome
2. 去 shopee.tw
3. 搜「iPhone 17 手機殼」
4. 過濾 < $500
5. 加購物車
6. 回報結果

## 用途範例
- **電商比價**：跨平台抓最低價
- **填表單**：政府網站 / 報名 / 報稅
- **資料整理**：抓 LinkedIn / 蝦皮資料
- **自動化測試**：取代 Selenium
- **個人助理**：訂機票 / 訂餐廳

## 限制 + 風險
- ⚠️ **慢**：每步都要截圖 + LLM 判斷、10 倍慢
- ⚠️ **貴**：Claude opus 一次 task NT$ 10-100
- ⚠️ **可能出錯**：點錯按鈕、買錯東西
- ⚠️ **資安**：登入帳號給 AI 用要小心
- ⚠️ **網站可能擋**：偵測 bot

## 最佳實踐
- 沙箱環境（Docker / VM）跑 agent
- 限制可訪問 domain（whitelist）
- 重要操作（付錢 / 刪東西）要 human in the loop
- log 所有動作、可審計

## 2026 主流工具
- **Anthropic Computer Use**：最強、付費
- **browser-use**：開源、免費
